      { q: 'SWOT-এর কোনটি বাহ্যিক বিষয়?', opts: ['সুযোগ ও হুমকি', 'শক্তি ও দুর্বলতা', 'শক্তি ও সুযোগ', 'দুর্বলতা ও হুমকি'], ans: 0 },
      { q: 'বাংলাদেশের ফার্মা শিল্প Industry Life Cycle-এর কোন পর্যায়ে?', opts: ['Growth', 'Pioneer', 'Decline', 'সবেমাত্র শুরু'], ans: 0 },
      { q: 'কোম্পানির "Moat" বলতে কী বোঝায়?', opts: ['প্রতিযোগিতামূলক সুবিধা যা অন্যরা সহজে নকল করতে পারে না', 'কোম্পানির মোট সম্পদ', 'কোম্পানির ঋণের পরিমাণ', 'কোম্পানির কর্মী সংখ্যা'], ans: 0 }
